+            }
+        },
+        .binop => |binop| {
+            try collectReferencedVarsInExpr(binop.left.*, vars, allocator);
+            try collectReferencedVarsInExpr(binop.right.*, vars, allocator);
+        },
+        .compare => |cmp| {
+            try collectReferencedVarsInExpr(cmp.left.*, vars, allocator);
+            for (cmp.comparators) |comp| {
