+            }
+            for (dict.values) |val| {
+                try collectReferencedVarsInExpr(val, vars, allocator);
+            }
+        },
+        .starred => |starred| {
+            try collectReferencedVarsInExpr(starred.value.*, vars, allocator);
+        },
+        .tuple => |tuple| {
+            for (tuple.elts) |elem| {
+                try collectReferencedVarsInExpr(elem, vars, allocator);
+            }
+        },
+        .boolop => |boolop| {
+            for (boolop.values) |val| {
