+            }
+        },
+        .if_expr => |if_expr| {
+            try collectReferencedVarsInExpr(if_expr.condition.*, vars, allocator);
+            try collectReferencedVarsInExpr(if_expr.body.*, vars, allocator);
+            try collectReferencedVarsInExpr(if_expr.orelse_value.*, vars, allocator);
+        },
+        else => {},
+    }
+}
